import type { Column, Record } from "elements";
import { Button } from "elements";
import { h } from "vue";
import type { Order, OrderStatus } from "./types";

export interface OrderColumnHandlers {
  onView: (order: Order) => void;
  onCancel: (order: Order) => void;
}

// Status label and CSS class lookup map
const STATUS_MAP: Record<OrderStatus, { label: string; class: string }> = {
  pending: { label: "Pending", class: "status-pending" },
  processing: { label: "Processing", class: "status-processing" },
  shipped: { label: "Shipped", class: "status-shipped" },
  delivered: { label: "Delivered", class: "status-delivered" },
  cancelled: { label: "Cancelled", class: "status-cancelled" },
};

// Currency formatter for USD
const currencyFormatter = new Intl.NumberFormat("en-US", {
  style: "currency",
  currency: "USD",
});

// Date formatter for medium style
const dateFormatter = new Intl.DateTimeFormat("en-US", {
  dateStyle: "medium",
});

export const createColumns = (
  handlers: OrderColumnHandlers,
): Column<Order>[] => [
  {
    id: "id",
    label: "Order",
    cell: ({ row }) => {
      return h("span", { class: "font-mono" }, `#ORD-${row.original.id}`);
    },
  },
  {
    id: "customer",
    label: "Customer",
    isSortable: true,
  },
  {
    id: "status",
    label: "Status",
    cell: ({ row }) => {
      const status = row.original.status;
      const { label, class: cssClass } = STATUS_MAP[status];
      return h("span", { class: cssClass }, label);
    },
  },
  {
    id: "items",
    label: "Items",
    isSortable: true,
  },
  {
    id: "total",
    label: "Total",
    isSortable: true,
    cell: ({ value }) => currencyFormatter.format(value as number),
  },
  {
    id: "date",
    label: "Date",
    isSortable: true,
    cell: ({ value }) => dateFormatter.format(new Date(value as string)),
  },
  {
    id: "actions",
    label: "",
    cell: ({ row }) => [
      h(
        Button,
        {
          variant: "ghost",
          size: "sm",
          onClick: () => handlers.onView(row.original),
        },
        () => "View",
      ),
      h(
        Button,
        {
          variant: "destructive",
          size: "sm",
          onClick: () => handlers.onCancel(row.original),
        },
        () => "Cancel",
      ),
    ],
  },
];

