    isSortable: true,
    cell: ({ row }) => dateFormatter.format(new Date(row.getValue("date"))),
  },
  {
    id: "actions",
    cell: ({ row }) => [
      h(
        "a",
        {
          style: "padding: 0.25rem 0.5rem; color: #3b82f6; text-decoration: none; font-size: 0.875rem;",
          onClick: () => handlers.onView(row.original),
        },
        "View",
      ),
      h(
        "a",
        {
          style: "padding: 0.25rem 0.5rem; color: #ef4444; text-decoration: none; font-size: 0.875rem; margin-left: 0.5rem;",
          onClick: () => handlers.onCancel(row.original),
        },
        "Cancel",
      ),
    ],
  },
];

import type { Column } from "elements";
import { h } from "vue";
import type { Order, OrderStatus, OrderColumnHandlers } from "./types";

const statusLabelMap: Record<OrderStatus, string> = {
  pending: "Pending",
  processing: "Processing",
  shipped: "Shipped",
  delivered: "Delivered",
  cancelled: "Cancelled",
} as const;

const statusClasses: Record<OrderStatus, string> = {
  pending: "status-pending",
  processing: "status-processing",
  shipped: "status-shipped",
  delivered: "status-delivered",
  cancelled: "status-cancelled",
} as const;

const totalFormatter = new Intl.NumberFormat("en-US", {
  style: "currency",
  currency: "USD",
});

const dateFormatter = new Intl.DateTimeFormat("en-US", {
  dateStyle: "medium",
});

const cellClassBadge = "inline-flex items-center rounded-full px-2 py-1 text-xs font-medium";

export const createColumns = (handlers: OrderColumnHandlers): Column<Order>[] => [
  {
    id: "id",
    label: "Order",
    cell: ({ row }) =>
      h("span", { class: "font-mono" }, `#${row.getValue("id")}`),
  },
  {
    id: "customer",
    label: "Customer",
    isSortable: true,
  },
  {
    id: "status",
    label: "Status",
    cell: ({ row }) => {
      const status = row.getValue("status") as OrderStatus;
      return h(
        "span",
        { class: `${cellClassBadge} ${statusClasses[status]}` },
        statusLabelMap[status],
      );
    },
  },
  {
    id: "items",
    label: "Items",
    isSortable: true,
  },
  {
    id: "total",
    label: "Total",
    isSortable: true,
    cell: ({ row }) => h("div", { class: "text-right font-medium" }, totalFormatter.format(row.getValue("total") as number)),
  },
  {
    id: "date",
    label: "Date",
    isSortable: true,
    cell: ({ row }) =>
      h("span", { class: "text-sm text-gray-600" }, dateFormatter.format(new Date(row.getValue("date") as string))),
  },
  {
    id: "actions",
    cell: ({ row }) => [
      h("a", { class: "px-2 py-1 text-sm text-blue-600 cursor-pointer", onClick: () => handlers.onView(row.original) }, "View"),
      h("a", { class: "px-2 py-1 text-sm text-red-600 cursor-pointer ml-2", onClick: () => handlers.onCancel(row.original) }, "Cancel"),
    ],
  },
];
